    "fields": {
      "summary": "Build Junior Developer agent (autonomous easy path)",
      "description": {
        "content": [
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Description",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Create the Junior Developer agent: a headless Claude Code session that picks up a ticket flagged \"easy\" by the Development Orchestrator, plans and implements the change, pushes a branch, and opens a PR.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Three files to create:",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/junior-dev/prompt.md",
                "type": "text"
              },
              {
                "text": " — prompt modeled on ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/jira-ticket/prompt.md",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/junior-dev/README.md",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".github/workflows/junior-dev.yml",
                "type": "text"
              },
              {
                "text": " — modeled on ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".github/workflows/jira-ticket.yml",
                "type": "text"
              },
              {
                "text": "; triggered via ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "workflow_dispatch",
                "type": "text"
              },
              {
                "text": " (with a ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "ticket_key",
                "type": "text"
              },
              {
                "text": " input) and/or ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "repository_dispatch",
                "type": "text"
              },
              {
                "text": " from the orchestrator",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Context",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Completes the easy-path lane of the agentic workflow (",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "docs/agentic-workflow.md",
                "type": "text"
              },
              {
                "text": "). Without this agent the Development Orchestrator (KAN-1) has no autonomous implementation path for simple tickets. This ticket also unblocks the Testing agent (KAN-3), which depends on the branch naming pattern defined here.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Implementation decisions (pick one each; document the choice in README)",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "marks": [
                  {
                    "type": "strong"
                  }
                ],
                "text": "Prompt framing:",
                "type": "text"
              },
              {
                "text": " ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "docs/agentic-workflow.md",
                "type": "text"
              },
              {
                "text": " names ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "/goal",
                "type": "text"
              },
              {
                "text": " and ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "/ralph-loop",
                "type": "text"
              },
              {
                "text": " as candidate approaches. Neither exists as a skill in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": ".claude/skills/",
                "type": "text"
              },
              {
                "text": " yet — the implementer must define the approach (create a skill there, or frame the prompt directly). Document the chosen approach in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "agents/junior-dev/README.md",
                "type": "text"
              },
              {
                "text": ".",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "marks": [
                  {
                    "type": "strong"
                  }
                ],
                "text": "Stop condition",
                "type": "text"
              },
              {
                "text": " (prevents an infinite loop on a hard ticket — pick one):",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "--max-turns N",
                "type": "text"
              },
              {
                "text": " on the action",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- An attempt counter committed back to the ticket as a label or comment",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- Workflow-level timeout",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "marks": [
                  {
                    "type": "strong"
                  }
                ],
                "text": "Branch naming:",
                "type": "text"
              },
              {
                "text": " Define a convention (e.g. ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "junior-dev/\u003cticket-key\u003e",
                "type": "text"
              },
              {
                "text": ") in the README. The Testing agent (KAN-3) uses this as a ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "pull_request",
                "type": "text"
              },
              {
                "text": " branch filter.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Acceptance Criteria",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "Dispatching the workflow with a real KAN ticket key produces a branch and a PR.",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "Run log committed under ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": ".github/agent-logs/junior-dev/\u003cDATE\u003e/\u003cRUN_ID\u003e.json",
                        "type": "text"
                      },
                      {
                        "text": " (matching the convention at ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": ".github/workflows/jira-ticket.yml",
                        "type": "text"
                      },
                      {
                        "text": " lines 99-116).",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "The chosen stop condition is documented in the README and exercised in a deliberate failure scenario.",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "text": "Branch naming convention is defined in ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": "agents/junior-dev/README.md",
                        "type": "text"
                      },
                      {
                        "text": ".",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              }
            ],
            "type": "bulletList"
          }
